mapper.select:
SELECT
    o.id as id,
    o.customer_id as customerId,
    u.email as customerEmail,
    o.state_id as stateId,
    o.total_amount as totalAmount,
    o.currency as currency,
    o.order_number as orderNumber,
    o.created_time as createdAt
FROM orders o
LEFT JOIN user_profiles u ON o.customer_id = u.id

    AND o.id = #{id}
    AND o.customer_id = #{customerId}
    AND u.email LIKE CONCAT('%', #{customerEmail}, '%')
    AND o.state_id = #{stateId}
    AND o.created_time >= #{startDate}
    AND o.created_time <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM orders o
LEFT JOIN user_profiles u ON o.customer_id = u.id

    AND o.id = #{id}
    AND o.customer_id = #{customerId}
    AND u.email LIKE CONCAT('%', #{customerEmail}, '%')
    AND o.state_id = #{stateId}
    AND o.created_time >= #{startDate}
    AND o.created_time <= #{endDate}
